def get_interpretation(planet_name: str, sign_index: int) -> str:
    if planet_name == "Sun":
        return SUN_TEXTS.get(sign_index, "")
    elif planet_name == "Moon":
        return MOON_TEXTS.get(sign_index, "")
    elif planet_name == "Chiron":
        return CHIRON_TEXTS.get(sign_index, "")
    return f"{planet_name} en {SIGN_NAMES[sign_index]}"
